# VS Code extension ID -> CLI tool mapping
# Format: extension_id<TAB>tool_name<TAB>notes (optional)
# Extension IDs are matched case-insensitively.
# Only extensions that imply a system-level CLI tool or language runtime.
# Tool names appear in REVIEW hints, not INSTALL records.

# Python linters and formatters
charliermarsh.ruff	ruff	Linter and formatter
ms-python.black-formatter	black	Formatter
ms-python.mypy-type-checker	mypy	Type checker
ms-python.pylint	pylint	Linter
ms-python.isort	isort	Import sorter
ms-python.flake8	flake8	Linter
ms-python.vscode-pylance	pyright	Pylance bundles pyright; the CLI is pyright

# Python runtime
ms-python.python	python3	Python runtime

# JavaScript / TypeScript / Web
dbaeumer.vscode-eslint	eslint	JS/TS linter
esbenp.prettier-vscode	prettier	Formatter
biomejs.biome	biome	Linter and formatter
denoland.vscode-deno	deno	Deno runtime

# Go
golang.go	go	Go toolchain

# Rust
rust-lang.rust-analyzer	rust-analyzer	Rust language server

# Zig
ziglang.vscode-zig	zig	Zig toolchain

# .NET / C#
